#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100005
#define INF 1000000000

// Structure to represent an edge
typedef struct Edge {
    int u, v, weight;
} Edge;

// Comparison function for sorting edges
int compare(const void *a, const void *b) {
    Edge *e1 = (Edge *)a;
    Edge *e2 = (Edge *)b;
    return e2->weight - e1->weight;
}

// Function to find the parent of a node
int find(int *parent, int i) {
    if (parent[i] == i)
        return i;
    return find(parent, parent[i]);
}

// Function to union two nodes
void unionSet(int *parent, int *rank, int u, int v) {
    int x = find(parent, u);
    int y = find(parent, v);
    if (rank[x] < rank[y])
        parent[x] = y;
    else if (rank[x] > rank[y])
        parent[y] = x;
    else {
        parent[y] = x;
        rank[x]++;
    }
}

