public class Main {
    static class Edge implements Comparable<Edge> {
        int u, v, weight;
        public Edge(int u, int v, int weight) {
            this.u = u;
            this.v = v;
            this.weight = weight;
        }
        @Override
        public int compareTo(Edge o) {
            return o.weight - weight;
        }
    }

    public static int find(int[] parent, int i) {
        if (parent[i] == i)
            return i;
        return find(parent, parent[i]);
    }

    public static void unionSet(int[] parent, int[] rank, int u, int v) {
        int x = find(parent, u);
        int y = find(parent, v);
        if (rank[x] < rank[y])
            parent[x] = y;
        else if (rank[x] > rank[y])
            parent[y] = x;
        else {
            parent[y] = x;
            rank[x]++;
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] Go = new int[N];
            int[] Tr = new int[N];
            for (int i = 0; i < N; i++)
                Go[i] = sc.nextInt();
            for (int i = 0; i < N; i++)
                Tr[i] = sc.nextInt();
            Edge[] edges = new Edge[N * N];
            int edgeCount = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    edges[edgeCount] = new Edge(i, j, (Go[i] | Go[j]) + (Tr[i] & Tr[j]));
                    edgeCount++;
                }
            }
            Arrays.sort(edges, 0, edgeCount);
            int[] parent = new int[N];
            int[] rank = new int[N];
            for (int i = 0; i < N; i++) {
                parent[i] = i;
                rank[i] = 0;
            }
            int mstWeight = 0;
            for (int i = 0; i < edgeCount; i++) {
                int u = edges[i].u;
                int v = edges[i].v;
                int weight = edges[i].weight;
                if (find(parent, u) != find(parent, v)) {
                    unionSet(parent, rank, u, v);
                    mstWeight += weight;
                }
            }
            System.out.println(mstWeight);
        }
    }
}

